module clock_divider #(
 parameter DIV_FACTOR = 8
)(
 input clk,
 input rst,
 output reg clk_out
);

 localparam MAX_COUNT = DIV_FACTOR / 2 - 1;
 integer count;

 always @(posedge clk or posedge rst) begin
 if (rst) begin
 count <= 0;
 clk_out <= 0;
 end else begin
 if (count == MAX_COUNT) begin
 clk_out <= ~clk_out;
 count <= 0;
 end else begin
 count <= count + 1;
 end
 end
 end
endmodule

entity d_ff_sync is
 Port ( clk : in STD_LOGIC;
 rst : in STD_LOGIC;
 d : in STD_LOGIC;
 q : out STD_LOGIC);
end d_ff_sync;

architecture Behavioral of d_ff_sync is
begin
 process(clk)
 begin
 if rising_edge(clk) then
 if rst = '1' then
 q <= '0';
 else
 q <= d;
 end if;
 end if;
 end process;
end Behavioral;

module two_phase_clock (
 input clk,
 input rst,
 output reg phi1,
 output reg phi2
);

 parameter PHASE_WIDTH = 4;

 always @(posedge clk or posedge rst) begin
 if (rst) begin
 phi1 <= 0;
 phi2 <= 0;
 end else begin
 // Generate phi1 for first half
 phi1 <= (counter < PHASE_WIDTH/2);
 // Generate phi2 for second half with gap
 phi2 <= (counter >= PHASE_WIDTH/2 && 
 counter < PHASE_WIDTH-1);
 counter <= counter + 1;
 end
 end
endmodule

// 2-Stage Synchronizer to reduce metastability
// Used at asynchronous boundaries

MODULE TwoStageSynchronizer(input async_signal, clk, output sync_signal)
BEGIN
 REGISTER stage1, stage2 // Two flip-flops in series

 // On every clock edge, pass signal through stages
 AT clock_posedge:
 stage1 <= async_signal // First stage may go metastable
 stage2 <= stage1 // Second stage settles to valid level
 sync_signal <= stage2 // Clean synchronous output

 RETURN sync_signal
END

